import org.eclipse.rdf4j.query.algebra.equivalence.AlgebraEquivalenceChecker;
import org.eclipse.rdf4j.query.algebra.equivalence.EquivalenceResult;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationCase;
import org.eclipse.rdf4j.query.algebra.equivalence.EvaluationOutcome;
import org.eclipse.rdf4j.query.algebra.equivalence.ObservationMode;
import org.eclipse.rdf4j.query.impl.MapBindingSet;
import org.eclipse.rdf4j.query.impl.SimpleDataset;
import org.junit.jupiter.api.Test;

class RuntimeEquivalenceDifferentialTest {
	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI P1 = VF.createIRI("urn:test:p1");
	private static final IRI P2 = VF.createIRI("urn:test:p2");
	private static final IRI P3 = VF.createIRI("urn:test:p3");
	private static final Resource SUBJECT = VF.createIRI("urn:test:subject");
	private static final IRI GRAPH_1 = VF.createIRI("urn:test:g1");
	private static final IRI GRAPH_2 = VF.createIRI("urn:test:g2");

	@Test
	void everyProvedRuntimePairAgreesAcrossExactEvaluationMatrix() {
		AlgebraEquivalenceChecker checker = new AlgebraEquivalenceChecker();
		Rdf4jEvaluator evaluator = new Rdf4jEvaluator();
		List<EvaluationCase> matrix = evaluationMatrix();

		for (EquivalentPair pair : equivalentPairs()) {
			EquivalenceResult proof = checker.check(pair.original(), pair.candidate());
			assertTrue(proof.isEquivalent(), () -> pair.label() + ": " + proof.getReason());
			for (EvaluationCase evaluationCase : matrix) {
				EvaluationAttempt originalAttempt = evaluator.evaluate(pair.original(), evaluationCase, 10_000);
				EvaluationAttempt candidateAttempt = evaluator.evaluate(pair.candidate(), evaluationCase, 10_000);
				assertTrue(originalAttempt.isComplete(),
						pair.label() + " original incomplete on " + evaluationCase.getLabel());
				assertTrue(candidateAttempt.isComplete(),
						pair.label() + " candidate incomplete on " + evaluationCase.getLabel());
				EvaluationOutcome original = originalAttempt.getOutcome().orElseThrow();
				EvaluationOutcome candidate = candidateAttempt.getOutcome().orElseThrow();
				assertFalse(original.hasError(), pair.label() + " original errored on " + evaluationCase.getLabel());
				assertFalse(candidate.hasError(), pair.label() + " candidate errored on " + evaluationCase.getLabel());
				assertTrue(
						original.sameAs(candidate, ObservationMode.BAG),
						() -> pair.label() + " differs on " + evaluationCase.getLabel()
								+ ": " + original + " versus " + candidate);
			}
		}
	}

	private static List<EquivalentPair> equivalentPairs() {
		StatementPattern a = pattern(P1, "x");
		StatementPattern b = pattern(P2, "y");
		StatementPattern c = pattern(P3, "z");
		Compare condition = new Compare(
				Var.of("x"),
				new ValueConstant(VF.createIRI("urn:test:object")),
				Compare.CompareOp.EQ);
		List<EquivalentPair> result = new ArrayList<>();
		result.add(new EquivalentPair(
				"structural clone",
				a.clone(),
				a.clone()));
		result.add(new EquivalentPair(
				"independent join order",
				new Join(a.clone(), b.clone()),
				new Join(b.clone(), a.clone())));
		result.add(new EquivalentPair(
				"bag union order",
				new Union(a.clone(), b.clone()),
				new Union(b.clone(), a.clone())));
		result.add(new EquivalentPair(
				"stable filter pushdown",
				new Filter(new Join(a.clone(), b.clone()), condition.clone()),
				new Join(new Filter(a.clone(), condition.clone()), b.clone())));
		result.add(new EquivalentPair(
				"left join distribution",
				new LeftJoin(new Union(a.clone(), b.clone()), c.clone()),
				new Union(new LeftJoin(a.clone(), c.clone()), new LeftJoin(b.clone(), c.clone()))));
		result.add(new EquivalentPair(
				"minus right union chain",
				new Difference(a.clone(), new Union(b.clone(), c.clone())),
				new Difference(new Difference(a.clone(), b.clone()), c.clone())));
		result.add(new EquivalentPair(
				"join unit",
				new Join(a.clone(), new SingletonSet()),
				a.clone()));
		return result;
	}

	private static List<EvaluationCase> evaluationMatrix() {
		IRI object = VF.createIRI("urn:test:object");
		List<EvaluationCase> result = new ArrayList<>();
		result.add(EvaluationCase.builder("empty dataset").build());
		result.add(EvaluationCase.builder("default graph with duplicate-producing mappings")
				.addStatement(VF.createStatement(SUBJECT, P1, object))
				.addStatement(VF.createStatement(SUBJECT, P2, object))
				.addStatement(VF.createStatement(SUBJECT, P3, VF.createLiteral("third")))
				.build());

		SimpleDataset namedAsDefault = new SimpleDataset();
		namedAsDefault.addDefaultGraph(GRAPH_1);
		namedAsDefault.addDefaultGraph(GRAPH_2);
		result.add(EvaluationCase.builder("two named graphs merged as default")
				.dataset(namedAsDefault)
				.addStatement(VF.createStatement(SUBJECT, P1, object, GRAPH_1))
				.addStatement(VF.createStatement(SUBJECT, P2, object, GRAPH_2))
				.build());

		SimpleDataset namedOnly = new SimpleDataset();
		namedOnly.addNamedGraph(GRAPH_1);
		result.add(EvaluationCase.builder("named graph only")
				.dataset(namedOnly)
				.addStatement(VF.createStatement(SUBJECT, P1, object, GRAPH_1))
				.build());

		MapBindingSet subjectBinding = new MapBindingSet();
		subjectBinding.setBinding("s", SUBJECT);
		result.add(EvaluationCase.builder("incoming subject binding")
				.initialBindings(subjectBinding)
				.addStatement(VF.createStatement(SUBJECT, P1, object))
				.addStatement(VF.createStatement(SUBJECT, P2, object))
				.build());

		MapBindingSet partialBinding = new MapBindingSet();
		partialBinding.setBinding("x", object);
		result.add(EvaluationCase.builder("partial object mapping")
				.initialBindings(partialBinding)
				.addStatement(VF.createStatement(SUBJECT, P1, object))
				.addStatement(VF.createStatement(SUBJECT, P2, object))
				.build());

		TripleTerm triple = VF.createTripleTerm(SUBJECT, P1, object);
		result.add(EvaluationCase.builder("RDF 1.2 terms")
				.addStatement(VF.createStatement(SUBJECT, P1, triple))
				.addStatement(VF.createStatement(
						SUBJECT,
						P2,
						VF.createLiteral("directional", "en", org.eclipse.rdf4j.model.Literal.BaseDirection.RTL)))
				.build());
		return result;
	}

	private static StatementPattern pattern(IRI predicate, String objectName) {
		return new StatementPattern(
				Var.of("s"),
				Var.of("const-" + predicate.stringValue(), predicate),
				Var.of(objectName));
	}

	private record EquivalentPair(String label, TupleExpr original, TupleExpr candidate) {
	}
}
